document.addEventListener('DOMContentLoaded', () => { lucide.createIcons(); window.addEventListener('load', () => { const loader = document.getElementById('loader'); if (loader) { setTimeout(() => { loader.classList.add('loaded'); setTimeout(() => { loader.style.display = 'none'; }, 500); }, 800); } }); const menuButton = document.querySelector('button[onclick="toggleMenu()"]'); if (menuButton) { menuButton.onclick = toggleMenu; } const observer = new IntersectionObserver((entries) => { entries.forEach(entry => { if (entry.isIntersecting) { entry.target.classList.add('opacity-100', 'translate-y-0'); entry.target.classList.remove('opacity-0', 'translate-y-10'); } }); }, { threshold: 0.05 }); document.querySelectorAll('section').forEach(section => { section.classList.add('transition-all', 'duration-1000', 'opacity-0', 'translate-y-10'); observer.observe(section); }); initHeroSlider(); }); function toggleMenu() { const menu = document.getElementById('mobile-menu'); menu.classList.toggle('active'); } function initHeroSlider() { const bgElement = document.getElementById('hero-bg'); const titleElement = document.getElementById('hero-title'); const descElement = document.getElementById('hero-desc'); if (!bgElement || !titleElement || !descElement) return; const slides = [ { image: "assets/images/hero-factory.jpg", title: 'SIVAM <span class="text-brand-orange">ITECH.</span>', desc: 'Pioneering precision at <span class="text-white font-semibold">SIVAM ITECH</span>. We combine industrial synergy with high-tech manufacturing to deliver excellence across automotive and structural sectors.' }, { image: "assets/images/hero-team.jpg", title: 'PRECISION <span class="text-brand-orange">COMPONENTS.</span>', desc: 'Delivering world-class components with micron-level tolerance. Our automated press lines and robotic assembly ensure zero-defect manufacturing for global leaders.' } ]; let currentSlide = 0; const intervalTime = 10000; setInterval(() => { currentSlide = (currentSlide + 1) % slides.length; const slide = slides[currentSlide]; titleElement.classList.add('opacity-0'); descElement.classList.add('opacity-0'); setTimeout(() => { bgElement.style.backgroundImage = `url('${slide.image}')`; titleElement.innerHTML = slide.title; descElement.innerHTML = slide.desc; titleElement.classList.remove('opacity-0'); descElement.classList.remove('opacity-0'); }, 500); }, intervalTime); }